/* Apply tabular figures to elements displaying numerical data */
.data-table td, 
.price-list li .amount, 
.statistic-value {
    font-feature-settings: "tnum"; /* Ensures numbers have consistent width for vertical alignment */
    /* Many fonts also support 'onum' (old style figures) or 'pnum' (proportional figures) */
}

/* Example: Enabling standard ligatures for improved readability in body text */
p.body-text {
    font-feature-settings: "liga", "clig"; /* Standard and contextual ligatures */
}

/* Example: Small caps for acronyms or initialisms */
.acronym {
    font-feature-settings: "smcp"; /* Renders lowercase letters as small capitals */
    text-transform: lowercase; /* Essential to allow smcp to work if input is uppercase */
}
